import React, { useState } from 'react';
import MapView from './components/MapView';
import SearchPanel from './components/SearchPanel';
import RouteInfoPanel from './components/RouteInfoPanel';
import DijkstraVisualizer from './components/DijkstraVisualizer';
import './index.css';

function App() {
  const [startPoint, setStartPoint] = useState(null);
  const [destPoint, setDestPoint] = useState(null);
  const [stops, setStops] = useState([]);

  const [mapCenter, setMapCenter] = useState([51.505, -0.09]);
  const [mapZoom, setMapZoom] = useState(13);

  const [routeData, setRouteData] = useState(null);
  const [showAnimation, setShowAnimation] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);

  const handleMapClick = (e) => {
    const { lat, lng } = e.latlng;
    if (!startPoint) {
      setStartPoint({ lat, lng, label: 'Selected Start' });
    } else if (!destPoint) {
      setDestPoint({ lat, lng, label: 'Selected Destination' });
    } else {
      setStops([...stops, { lat, lng, label: `Stop ${stops.length + 1}` }]);
    }
  };

  const calculateRoute = () => {
    if (!startPoint || !destPoint) return;
    setIsCalculating(true);
    // Simulating initialization. In DijkstraVisualizer, it handles the actual algorithm.
    // If we wanted to decouple, we would calculate it here. 
    // Given the component structure asked, we will trigger the visualizer.
  };

  return (
    <div className="app-container">
      <SearchPanel 
        startPoint={startPoint} setStartPoint={setStartPoint}
        destPoint={destPoint} setDestPoint={setDestPoint}
        stops={stops} setStops={setStops}
        setMapCenter={setMapCenter}
        onSearch={calculateRoute}
        isCalculating={isCalculating}
      />

      <MapView 
        center={mapCenter} 
        zoom={mapZoom} 
        onMapClick={handleMapClick}
        startPoint={startPoint}
        destPoint={destPoint}
        stops={stops}
      >
        {(startPoint && destPoint && isCalculating) && (
          <DijkstraVisualizer 
            startPoint={startPoint} 
            destPoint={destPoint} 
            stops={stops}
            showAnimation={showAnimation}
            onComplete={(data) => {
              setRouteData(data);
              setIsCalculating(false);
            }}
          />
        )}
      </MapView>

      {routeData && (
        <RouteInfoPanel 
          routeData={routeData} 
          showAnimation={showAnimation}
          setShowAnimation={setShowAnimation}
        />
      )}
    </div>
  );
}

export default App;

import React, { useEffect, useState, useRef } from 'react';
import { Polyline, CircleMarker } from 'react-leaflet';
import axios from 'axios';

const fetchOSMGraph = async (start, dest) => {
  const pad = 0.01;
  const minLat = Math.min(start.lat, dest.lat) - pad;
  const maxLat = Math.max(start.lat, dest.lat) + pad;
  const minLng = Math.min(start.lng, dest.lng) - pad;
  const maxLng = Math.max(start.lng, dest.lng) + pad;

  // Grab highway elements (excluding small paths if needed, but for demo grabbing most roads is fine)
  const query = `
    [out:json][timeout:25];
    (
      way["highway"](${minLat},${minLng},${maxLat},${maxLng});
    );
    (._;>;);
    out skel;
  `;

  const url = `https://overpass-api.de/api/interpreter?data=${encodeURIComponent(query)}`;
  const res = await axios.get(url);

  const nodes = {};
  const adjacency = {};

  // Phase 1: Initialize Nodes
  res.data.elements.forEach(el => {
    if (el.type === 'node') {
      nodes[el.id] = { id: el.id, lat: el.lat, lng: el.lon, distance: Infinity, visited: false, previousNode: null };
      adjacency[el.id] = [];
    }
  });

  // Phase 2: Build Edges mapping paths following the street nodes
  res.data.elements.forEach(el => {
    if (el.type === 'way' && el.nodes) {
      for (let i = 0; i < el.nodes.length - 1; i++) {
        const id1 = el.nodes[i];
        const id2 = el.nodes[i+1];
        if (nodes[id1] && nodes[id2]) {
          // Haversine distance could be used here. For simplicity, hypot in degrees works for local routing.
          const dist = Math.hypot(nodes[id1].lat - nodes[id2].lat, nodes[id1].lng - nodes[id2].lng);
          adjacency[id1].push({ id: id2, distance: dist });
          adjacency[id2].push({ id: id1, distance: dist }); // undirected graph
        }
      }
    }
  });

  // Snap start and dest to closest network nodes
  let startNodeId = null;
  let destNodeId = null;
  let minStartDist = Infinity;
  let minDestDist = Infinity;

  // Need an array for priority queue sorting later
  const unvisitedNodes = [];

  for (const id in nodes) {
    const node = nodes[id];
    unvisitedNodes.push(node);

    const dStart = Math.hypot(node.lat - start.lat, node.lng - start.lng);
    const dDest = Math.hypot(node.lat - dest.lat, node.lng - dest.lng);

    if (dStart < minStartDist) { minStartDist = dStart; startNodeId = node.id; }
    if (dDest < minDestDist) { minDestDist = dDest; destNodeId = node.id; }
  }

  return { nodes, adjacency, startNodeId, destNodeId, unvisitedNodes };
};

const DijkstraVisualizer = ({ startPoint, destPoint, showAnimation, onComplete }) => {
  const [visitedNodes, setVisitedNodes] = useState([]);

  // Requirement 2: Separate states for animation and final path
  const [animationPath, setAnimationPath] = useState([]); 
  const [finalPath, setFinalPath] = useState([]);

  const [loadingGraph, setLoadingGraph] = useState(false);

  const activeAlgorithm = useRef(false);

  useEffect(() => {
    if (!startPoint || !destPoint) return;

    // Only clear path when user selects new start/destination (Requirement 6)
    setVisitedNodes([]);
    setAnimationPath([]);
    setFinalPath([]); 

    const runAlgorithm = async () => {
      activeAlgorithm.current = true;
      setLoadingGraph(true);

      try {
        const { nodes, adjacency, startNodeId, destNodeId, unvisitedNodes } = await fetchOSMGraph(startPoint, destPoint);
        setLoadingGraph(false);

        if (!startNodeId || !destNodeId) {
          console.warn("Could not snap points to road network.");
          activeAlgorithm.current = false;
          return;
        }

        nodes[startNodeId].distance = 0;
        const visitedNodesInOrder = [];

        const animateDijkstra = () => {
          if (!unvisitedNodes.length || !activeAlgorithm.current) return;

          // Priority queue simplification
          unvisitedNodes.sort((a, b) => a.distance - b.distance);
          const closestNode = unvisitedNodes.shift();

          // If trapped
          if (closestNode.distance === Infinity) return;

          closestNode.visited = true;
          visitedNodesInOrder.push(closestNode);

          if (showAnimation) {
            setVisitedNodes([...visitedNodesInOrder]);
          }

          if (closestNode.id === destNodeId) {
            // Requirement 3: Calculate coordinates
            const pathCoordinates = [];
            let curr = closestNode;
            while (curr !== null) {
              pathCoordinates.unshift([curr.lat, curr.lng]);
              curr = curr.previousNode ? nodes[curr.previousNode] : null;
            }

            // Animate path sequentially
            if (showAnimation) {
              let currentStep = 0;
              const pathInterval = setInterval(() => {
                if (currentStep <= pathCoordinates.length) {
                  setAnimationPath(pathCoordinates.slice(0, currentStep));
                  currentStep++;
                } else {
                  clearInterval(pathInterval);
                  // Requirement 1 & 4 & 5: Set finalPath permanently
                  setFinalPath(pathCoordinates);
                  setAnimationPath([]); // Clean up animation line

                  finalizeRoute(pathCoordinates, visitedNodesInOrder.length);
                }
              }, 20); // Path follow speed along curve
            } else {
              setVisitedNodes(visitedNodesInOrder);
              setFinalPath(pathCoordinates);
              finalizeRoute(pathCoordinates, visitedNodesInOrder.length);
            }
            return;
          }

          // Evaluate Neighbors using actual road intersections
          const neighbors = adjacency[closestNode.id];
          for (const neighbor of neighbors) {
            const nextNode = nodes[neighbor.id];
            if (!nextNode.visited) {
              const alt = closestNode.distance + neighbor.distance;
              if (alt < nextNode.distance) {
                nextNode.distance = alt;
                nextNode.previousNode = closestNode.id;
              }
            }
          }

          if (showAnimation) {
            setTimeout(animateDijkstra, 5); // Faster animation since real world has thousands of nodes
          } else {
            animateDijkstra(); 
          }
        };

        const finalizeRoute = async (path, visitedCount) => {
          const approxDist = (Math.hypot(startPoint.lat - destPoint.lat, startPoint.lng - destPoint.lng) * 111).toFixed(2);

          try {
            await axios.post('http://localhost:5000/api/routes/save', {
              startLocation: startPoint,
              destinationLocation: destPoint,
              distance: approxDist,
              nodesExplored: visitedCount,
              path: path.map(p => ({ lat: p[0], lng: p[1] }))
            });
          } catch (err) {
            console.warn("Backend missing/failed, skipped persistence.");
          }

          onComplete({
            distance: approxDist + ' km',
            nodesExplored: visitedCount,
            totalSteps: visitedCount,
          });
          activeAlgorithm.current = false;
        };

        animateDijkstra();

      } catch (err) {
        console.error("OSM Graph Fetch Failed", err);
        setLoadingGraph(false);
      }
    };

    runAlgorithm();

    return () => { activeAlgorithm.current = false; };
  }, [startPoint, destPoint]);

  return (
    <>
      {/* Overpass loading indicator rendering directly on Map View */}
      {loadingGraph && (
        <div style={{ position: 'absolute', top: 120, left: '50%', transform: 'translateX(-50%)', zIndex: 1000, background: 'rgba(255,255,255,0.9)', padding: '8px 16px', borderRadius: '24px', boxShadow: '0 4px 12px rgba(0,0,0,0.1)', fontSize: '14px', fontWeight: 600 }}>
          Downloading OpenStreetMap Graph...
        </div>
      )}

      {/* Step-by-step explored nodes mapped to real intersections */}
      {showAnimation && visitedNodes.map((node, idx) => (
        <CircleMarker 
          key={`vn-${idx}`}
          center={[node.lat, node.lng]} 
          radius={2} // smaller radius for real-world dense intersections
          pathOptions={{ color: 'rgba(37, 99, 235, 0.4)', fillOpacity: 0.8, border: false }}
        />
      ))}

      {/* Requirement 7,8,10: Render Final route persistently. */}
      {finalPath.length > 0 && (
        <Polyline 
          positions={finalPath} 
          pathOptions={{ color: '#2563eb', weight: 6, opacity: 0.9, lineCap: 'round', lineJoin: 'round' }}
        />
      )}

      {/* Animation state rendered separately while calculating */}
      {showAnimation && finalPath.length === 0 && animationPath.length > 0 && (
        <Polyline 
          positions={animationPath} 
          pathOptions={{ color: '#ef4444', weight: 5, opacity: 0.8 }}
        />
      )}
    </>
  );
};

export default DijkstraVisualizer;

import React, { useEffect } from 'react';
import { MapContainer, TileLayer, useMapEvents, Marker, Popup, ZoomControl } from 'react-leaflet';
import L from 'leaflet';

// Create custom pulse icons
const createIcon = (type) => L.divIcon({
  className: 'custom-marker-icon',
  html: `<div class="pulse-marker ${type}"></div>`,
  iconSize: [20, 20],
  iconAnchor: [10, 10]
});

const startIcon = createIcon('start');
const destIcon = createIcon('dest');
const stopIcon = createIcon('stop');

// Component to handle clicks on map
function MapClickHandler({ onMapClick }) {
  useMapEvents({
    click: onMapClick,
  });
  return null;
}

// Component to dynamically pan map when center changes
function MapCenterer({ center, zoom }) {
  const map = useMapEvents({});
  useEffect(() => {
    if (center) {
      map.flyTo(center, map.getZoom(), {
        animate: true,
        duration: 1.5
      });
    }
  }, [center, map]);
  return null;
}

const MapView = ({ center, zoom, onMapClick, startPoint, destPoint, stops, children }) => {
  return (
    <div className="map-container">
      <MapContainer 
        center={center} 
        zoom={zoom} 
        style={{ height: '100%', width: '100%' }}
        zoomControl={false} // Disable default to place our own
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
          url="https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png" // Modern looking tile theme
        />
        <ZoomControl position="topright" />

        <MapClickHandler onMapClick={onMapClick} />
        <MapCenterer center={center} zoom={zoom} />

        {startPoint && (
          <Marker position={[startPoint.lat, startPoint.lng]} icon={startIcon}>
            <Popup>{startPoint.label}</Popup>
          </Marker>
        )}

        {destPoint && (
          <Marker position={[destPoint.lat, destPoint.lng]} icon={destIcon}>
            <Popup>{destPoint.label}</Popup>
          </Marker>
        )}

        {stops && stops.map((stop, idx) => (
          <Marker key={idx} position={[stop.lat, stop.lng]} icon={stopIcon}>
            <Popup>{stop.label}</Popup>
          </Marker>
        ))}

        {children}
      </MapContainer>
    </div>
  );
};

export default MapView;

